13	// routingDeprecationWarnOnce ensures the deprecated profile_priority +
14	// opt-in (profile_ladders / model_overrides) warnings fire only once per
15	// process even when LoadWithWorkingDir is called many times. Each key
16	// gets its own sync.Once.
17	var (
18		routingDeprecationWarnOnce sync.Map // key string -> *sync.Once
19	)
20	
21	func warnRoutingOnce(key, msg string) {
22		v, _ := routingDeprecationWarnOnce.LoadOrStore(key, &sync.Once{})
23		v.(*sync.Once).Do(func() {
24			fmt.Fprintln(os.Stderr, msg)
25		})
26	}
