28	// ResetRoutingDeprecationWarnings clears the one-time warning latches.
29	// Tests call this so each test case can observe the warning fresh.
30	func ResetRoutingDeprecationWarnings() {
31		routingDeprecationWarnOnce = sync.Map{}
32	}
