121	// Load loads configuration using the new simplified approach
122	func Load() (*Config, error) {
123		workingDir, err := os.Getwd()
124		if err != nil {
125			return nil, fmt.Errorf("failed to get working directory: %w", err)
126		}
127		return LoadWithWorkingDir(workingDir)
128	}
