228	// Merge combines this config with another, with the other taking precedence
229	func (c *Config) Merge(other *Config) *Config {
230		result := &Config{
231			Version: c.Version,
232		}
233	
234		// Copy library configuration from base
235		if c.Library != nil {
236			result.Library = &LibraryConfig{
237				Path: c.Library.Path,
238			}
239			if c.Library.Repository != nil {
240				result.Library.Repository = &RepositoryConfig{
241					URL:    c.Library.Repository.URL,
242					Branch: c.Library.Repository.Branch,
243				}
244			}
245		}
246	
247		// Override with other's values
248		if other.Version != "" {
249			result.Version = other.Version
250		}
251		if other.Library != nil {
252			if result.Library == nil {
253				result.Library = &LibraryConfig{}
254			}
255			if other.Library.Path != "" {
256				result.Library.Path = other.Library.Path
257			}
258			if other.Library.Repository != nil {
259				if result.Library.Repository == nil {
260					result.Library.Repository = &RepositoryConfig{}
261				}
262				if other.Library.Repository.URL != "" {
263					result.Library.Repository.URL = other.Library.Repository.URL
264				}
265				if other.Library.Repository.Branch != "" {
266					result.Library.Repository.Branch = other.Library.Repository.Branch
267				}
268			}
269		}
270	
271		return result
272	}
