1	package agent
2	
3	import (
4		"strings"
5		"sync/atomic"
6	
7		"github.com/DocumentDrivenDX/ddx/internal/config"
8		"github.com/DocumentDrivenDX/ddx/internal/escalation"
9	)
10	
11	const DefaultRoutingProfile = "default"
12	
13	var profileTierRank = map[string]int{
14		"cheap":    0,
15		"fast":     1,
16		"standard": 2,
17		"smart":    3,
18	}
19	
20	// Test seams: tests assert that ResolveProfileLadder and ResolveTierModelRef
21	// are NOT in the call graph on the default routing path (ddx-755f5881 AC #3).
22	// Production code never reads these counters; they are exported only for tests.
23	var (
24		resolveProfileLadderCalls atomic.Int64
25		resolveTierModelRefCalls  atomic.Int64
26	)
27	
28	// ResolveProfileLadderCallCount returns the current value of the call counter.
29	// Tests use it together with ResetRoutingCallCounters to verify call-graph claims.
30	func ResolveProfileLadderCallCount() int64 { return resolveProfileLadderCalls.Load() }
31	
32	// ResolveTierModelRefCallCount returns the current value of the call counter.
33	func ResolveTierModelRefCallCount() int64 { return resolveTierModelRefCalls.Load() }
34	
35	// ResetRoutingCallCounters zeros the test-seam counters.
36	func ResetRoutingCallCounters() {
37		resolveProfileLadderCalls.Store(0)
38		resolveTierModelRefCalls.Store(0)
39	}
40	
41	// ResolveProfileLadder returns the ordered tiers to try for profile after
42	// applying explicit --min-tier / --max-tier caps.
43	func ResolveProfileLadder(routing *config.RoutingConfig, profile, minTier, maxTier string) []escalation.ModelTier {
44		resolveProfileLadderCalls.Add(1)
45		profile = NormalizeRoutingProfile(profile)
46		ladder := routing.ResolvedLadder(profile)
47		out := make([]escalation.ModelTier, 0, len(ladder))
48		for _, raw := range ladder {
49			tier := strings.TrimSpace(raw)
50			if tier == "" || !tierWithinBounds(tier, minTier, maxTier) {
51				continue
52			}
53			out = append(out, escalation.ModelTier(tier))
54		}
55		return out
56	}
57	
58	func NormalizeRoutingProfile(profile string) string {
59		profile = strings.TrimSpace(profile)
60		if profile == "" {
61			return DefaultRoutingProfile
62		}
63		return profile
64	}
65	
66	// ResolveTierModelRef applies agent.routing.model_overrides for a ladder tier.
67	func ResolveTierModelRef(routing *config.RoutingConfig, tier escalation.ModelTier) string {
68		resolveTierModelRefCalls.Add(1)
69		tierRef := string(tier)
70		if routing != nil && routing.ModelOverrides != nil {
71			if override := strings.TrimSpace(routing.ModelOverrides[tierRef]); override != "" {
72				return override
73			}
74		}
75		return tierRef
76	}
77	
78	// TierCandidate is one (harness, model) pair to try for a ladder tier.
79	// It is produced by ResolveTierCandidates and consumed by the escalation
80	// loop in execute-loop. Source carries the provenance (override|catalog) so
81	// diagnostics can distinguish caller-provided overrides from defaults.
82	type TierCandidate struct {
83		Surface string // catalog surface (empty for override candidates)
84		Harness string // harness name (empty for override candidates — upstream picks)
85		Model   string // concrete model string to pass to ResolveRoute
86		Source  string // "override" or "catalog"
87	}
88	
89	// catalogSurfaceOrder is the deterministic order surfaces are tried within a
90	// tier. Walking surfaces in a stable order makes tier-attempt diagnostics
91	// reproducible across runs.
92	var catalogSurfaceOrder = []string{"codex", "claude", "embedded-openai"}
93	
94	// surfaceToHarnessName returns the harness name that owns a catalog surface.
95	// Inverse of harnessToSurface.
96	func surfaceToHarnessName(surface string) string {
97		for h, s := range harnessToSurface {
98			if s == surface {
99				return h
100			}
101		}
102		return ""
103	}
104	
105	// ResolveTierCandidates returns ordered (harness, model) candidates for a
106	// ladder tier. agent.routing.model_overrides wins when set (an override has
107	// no associated harness — upstream picks); catalog surfaces in
108	// catalogSurfaceOrder follow as defaults so projects without
109	// model_overrides still resolve a concrete model per tier via the catalog.
110	//
111	// Healthy-harness and provider-reachability checks are NOT performed here:
112	// callers should iterate the returned candidates and probe each via
113	// svc.ResolveRoute / svc.RouteStatus, recording per-candidate rejections in
114	// tier-attempt diagnostics. ResolveTierCandidates is purely the "what could
115	// be tried" enumeration.
116	func ResolveTierCandidates(routing *config.RoutingConfig, cat *Catalog, tier escalation.ModelTier) []TierCandidate {
117		var out []TierCandidate
118		tierStr := string(tier)
119	
120		if routing != nil && routing.ModelOverrides != nil {
121			if override := strings.TrimSpace(routing.ModelOverrides[tierStr]); override != "" {
122				out = append(out, TierCandidate{Model: override, Source: "override"})
123			}
124		}
125	
126		if cat == nil {
127			cat = BuiltinCatalog
128		}
129		if entry, ok := cat.Entry(tierStr); ok {
130			for _, surface := range catalogSurfaceOrder {
131				model, ok := entry.Surfaces[surface]
132				if !ok || strings.TrimSpace(model) == "" {
133					continue
134				}
135				if cat.IsBlockedModelID(model) {
136					continue
137				}
138				harness := surfaceToHarnessName(surface)
139				if harness == "" {
140					continue
141				}
142				out = append(out, TierCandidate{
143					Surface: surface,
144					Harness: harness,
145					Model:   model,
146					Source:  "catalog",
147				})
148			}
149		}
150		return out
151	}
152	
153	func tierWithinBounds(tier, minTier, maxTier string) bool {
154		rank, ok := profileTierRank[tier]
155		if !ok {
156			return minTier == "" && maxTier == ""
157		}
158		if minTier != "" {
159			if minRank, ok := profileTierRank[minTier]; ok && rank < minRank {
160				return false
161			}
162		}
163		if maxTier != "" {
164			if maxRank, ok := profileTierRank[maxTier]; ok && rank > maxRank {
165				return false
166			}
167		}
168		return true
169	}
