9	// TestAgentExecuteLoopEscalateFlagRecognized covers ddx-755f5881 AC #5:
10	// the --escalate flag remains a registered flag so the tier-ladder path
11	// stays reachable. Previously escalation was implicit-on whenever no
12	// harness/model was pinned; ddx-755f5881 made it opt-in.
13	func TestAgentExecuteLoopEscalateFlagRecognized(t *testing.T) {
14		t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")
15		dir := agentTestDir(t)
16		rootCmd := NewCommandFactory(dir).NewRootCommand()
17	
18		// --once short-circuits when no ready beads exist; --local avoids the
19		// server submission path. Pass --escalate to exercise the registration.
20		_, err := executeCommand(rootCmd, "agent", "execute-loop",
21			"--escalate", "--once", "--local",
22		)
23		if err != nil {
24			// The "unknown flag" error would mean the flag isn't registered;
25			// any other error (e.g. routing-related) is acceptable.
26			if errMsg := err.Error(); contains(errMsg, "unknown flag") {
27				t.Fatalf("--escalate must be a registered flag, got: %v", err)
28			}
29		}
30	}
