32	// TestAgentExecuteLoopDefaultPathDoesNotEscalate verifies that a default
33	// `ddx agent execute-loop --once --local` invocation (no --escalate) does
34	// not invoke the tier-ladder helpers. With no ready beads the loop exits
35	// before the executor is called, but ResolveProfileLadder/ResolveTierModelRef
36	// must still be untouched on this path.
37	func TestAgentExecuteLoopDefaultPathDoesNotEscalate(t *testing.T) {
38		t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")
39		dir := agentTestDir(t)
40		agent.ResetRoutingCallCounters()
41	
42		rootCmd := NewCommandFactory(dir).NewRootCommand()
43		_, _ = executeCommand(rootCmd, "agent", "execute-loop", "--once", "--local")
44	
45		if got := agent.ResolveProfileLadderCallCount(); got != 0 {
46			t.Errorf("ResolveProfileLadder must not be called on default execute-loop path, got %d", got)
47		}
48		if got := agent.ResolveTierModelRefCallCount(); got != 0 {
49			t.Errorf("ResolveTierModelRef must not be called on default execute-loop path, got %d", got)
50		}
51	}
